from dataclasses import dataclass, field

# Haiku pricing as of 2024 (per million tokens)
# Verify current pricing at https://www.anthropic.com/pricing
PRICING = {
    "claude-haiku-4-5-20251001": {
        "input_per_mtok": 0.80,   # $0.80 per million input tokens
        "output_per_mtok": 4.00,  # $4.00 per million output tokens
    },
}

@dataclass
class TokenBudget:
    """
    Tracks cumulative token usage and cost across agent iterations.
    Provides budget enforcement with configurable limits.
    """
    model: str
    max_input_tokens: int | None = None   # hard limit on cumulative input tokens
    max_cost_usd: float | None = None     # hard limit on total cost

    _total_input: int = field(default=0, init=False)
    _total_output: int = field(default=0, init=False)

    def record(self, input_tokens: int, output_tokens: int):
        self._total_input += input_tokens
        self._total_output += output_tokens

    @property
    def total_input_tokens(self) -> int:
        return self._total_input

    @property
    def total_output_tokens(self) -> int:
        return self._total_output

    @property
    def total_cost_usd(self) -> float:
        pricing = PRICING.get(self.model, {"input_per_mtok": 3.0, "output_per_mtok": 15.0})
        input_cost = self._total_input / 1_000_000 * pricing["input_per_mtok"]
        output_cost = self._total_output / 1_000_000 * pricing["output_per_mtok"]
        return input_cost + output_cost

    def is_exceeded(self) -> str | None:
        """Returns 'tokens' or 'cost' if a limit is exceeded, else None."""
        if self.max_input_tokens and self._total_input >= self.max_input_tokens:
            return "tokens"
        if self.max_cost_usd and self.total_cost_usd >= self.max_cost_usd:
            return "cost"
        return None

    def remaining_tokens(self) -> int | None:
        if self.max_input_tokens is None:
            return None
        return max(0, self.max_input_tokens - self._total_input)

    def summary(self) -> str:
        return (
            f"Input: {self._total_input:,} tokens, "
            f"Output: {self._total_output:,} tokens, "
            f"Cost: ${self.total_cost_usd:.4f}"
        )

# Example:
budget = TokenBudget(
    model="claude-haiku-4-5-20251001",
    max_input_tokens=50_000,
    max_cost_usd=0.05,
)

