import anthropic
import json

client = anthropic.Anthropic()

BASE_SYSTEM = """
You are a research assistant. Use the search tool to find information.
Call task_complete when you have enough information to answer the question.
Call task_failed if the question cannot be answered.
"""

def build_system_with_budget(base: str, budget: TokenBudget) -> str:
    remaining = budget.remaining_tokens()
    if remaining is None:
        return base
    pct = (remaining / budget.max_input_tokens) * 100 if budget.max_input_tokens else 100
    if pct < 25:
        urgency = (
            f"\n\nBUDGET WARNING: Only {remaining:,} input tokens remain (<25% of budget). "
            "Make at most 1-2 more tool calls, then synthesise and call task_complete."
        )
    elif pct < 50:
        urgency = (
            f"\n\nBudget note: {remaining:,} input tokens remain (about {pct:.0f}%). "
            "Prioritise the most important remaining calls."
        )
    else:
        urgency = ""
    return base + urgency

def run_budgeted_agent(user_message: str, tier: TaskTier, tools: list, dispatch: dict) -> dict:
    budget = get_budget(tier)
    messages = [{"role": "user", "content": user_message}]

    for iteration in range(1, 20):
        system = build_system_with_budget(BASE_SYSTEM, budget)
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=system,
            tools=tools,
            messages=messages,
        )
        budget.record(resp.usage.input_tokens, resp.usage.output_tokens)
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "result": block.input,
                        "budget": budget.summary()}

        exceeded = budget.is_exceeded()
        if exceeded:
            return {"status": f"budget_{exceeded}", "budget": budget.summary()}

        if not tool_calls:
            return {"status": "no_tool_calls", "budget": budget.summary()}

        results = []
        for block in tool_calls:
            fn = dispatch.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

    return {"status": "max_iterations", "budget": budget.summary()}

class AdaptiveIterationBudget:
    """
    Computes a token-aware iteration cap in real time.
    As the cost per iteration is observed, re-estimates how many iterations remain.
    """
    def __init__(self, total_token_budget: int, min_iterations: int = 3):
        self.total_token_budget = total_token_budget
        self.min_iterations = min_iterations
        self._spent = 0
        self._iteration_costs: list[int] = []

    def record(self, tokens_this_iteration: int):
        self._spent += tokens_this_iteration
        self._iteration_costs.append(tokens_this_iteration)

    @property
    def average_cost_per_iteration(self) -> float:
        if not self._iteration_costs:
            return 0.0
        # Use the last 3 iterations for a rolling average
        recent = self._iteration_costs[-3:]
        return sum(recent) / len(recent)

    @property
    def remaining_tokens(self) -> int:
        return max(0, self.total_token_budget - self._spent)

    @property
    def estimated_remaining_iterations(self) -> int:
        avg = self.average_cost_per_iteration
        if avg <= 0:
            return self.min_iterations
        estimated = int(self.remaining_tokens / avg)
        return max(self.min_iterations, estimated)

    def should_stop(self) -> bool:
        return self.remaining_tokens <= 0

    def status(self) -> dict:
        return {
            "spent": self._spent,
            "remaining": self.remaining_tokens,
            "avg_per_iter": round(self.average_cost_per_iteration),
            "est_remaining_iters": self.estimated_remaining_iterations,
        }

# Example: budget of 30,000 tokens, iterations cost 3,000-6,000 each
budget = AdaptiveIterationBudget(total_token_budget=30_000)

iteration_costs = [3000, 4000, 6000, 5000, 5500]
for i, cost in enumerate(iteration_costs, 1):
    budget.record(cost)
    status = budget.status()
    print(
        f"After iter {i}: spent={status['spent']:,}, "
        f"remaining={status['remaining']:,}, "
        f"avg={status['avg_per_iter']:,}, "
        f"est_iters_left={status['est_remaining_iters']}"
    )
    if budget.should_stop():
        print("Budget exhausted.")
        break
